public int specialArray(int[] nums) {
    int max_val = Arrays.stream(nums).max().orElse(0);
    for (int x = 1; x <= max_val; ++x) {
        int count = 0;
        for (int num : nums) {
            if (num >= x) count++;
        }
        if (count == x) return x;
    }
    return -1;
}
```

